static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    // Shapes: x [N, K], weight [C, K], output y [N, C]
    const auto *x_shape = context->GetInputShape(0);
    const auto *w_shape = context->GetInputShape(1);
    if (x_shape == nullptr || w_shape == nullptr) {
        return ge::GRAPH_FAILED;
    }
    const uint64_t N64 = x_shape->GetOriginShape().GetDim(0);
    const uint64_t K64 = x_shape->GetOriginShape().GetDim(1);
    const uint64_t C64 = w_shape->GetOriginShape().GetDim(0);
    if (N64 == 0 || K64 == 0 || C64 == 0) { return ge::GRAPH_FAILED; }
    const uint32_t N = static_cast<uint32_t>(N64);
    const uint32_t K = static_cast<uint32_t>(K64);
    const uint32_t C = static_cast<uint32_t>(C64);

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *numGroupsPtr = attrs->GetAttrPointer<int32_t>(0);
    const float *epsPtr = attrs->GetAttrPointer<float>(1);
    const float *htMinPtr = attrs->GetAttrPointer<float>(2);
    const float *htMaxPtr = attrs->GetAttrPointer<float>(3);
    if (numGroupsPtr == nullptr) { return ge::GRAPH_FAILED; }
    const uint32_t G = static_cast<uint32_t>(*numGroupsPtr);
    const float eps = (epsPtr ? *epsPtr : 1e-5f);
    const float htMin = (htMinPtr ? *htMinPtr : -1.0f);
    const float htMax = (htMaxPtr ? *htMaxPtr : 1.0f);

    if (C % G != 0) { return ge::GRAPH_FAILED; }

    // Build Matmul tiling for NORMAL layout with A: [N,K] FP16, B: [C,K] FP16 (transpose in kernel), C: [N,C] FP32
    auto ascendcPlatform = platform_ascendc::PlatformAscendC(context->GetPlatformInfo());
    matmul_tiling::MultiCoreMatmulTiling mtiling(ascendcPlatform);

    // Let tiler decide blockDim and splitting
    mtiling.SetDim(1);
    mtiling.SetAType(matmul_tiling::TPosition::GM, matmul_tiling::CubeFormat::ND, matmul_tiling::DataType::DT_FLOAT16);
    mtiling.SetBType(matmul_tiling::TPosition::GM, matmul_tiling::CubeFormat::ND, matmul_tiling::DataType::DT_FLOAT16);
    mtiling.SetCType(matmul_tiling::TPosition::GM, matmul_tiling::CubeFormat::ND, matmul_tiling::DataType::DT_FLOAT);
    mtiling.SetBiasType(matmul_tiling::TPosition::GM, matmul_tiling::CubeFormat::ND, matmul_tiling::DataType::DT_FLOAT);
    mtiling.SetShape(N, C, K);
    mtiling.SetSingleShape(N, C, K);
    mtiling.SetOrgShape(N, C, K);
    mtiling.SetBias(true);
    mtiling.SetBufferSpace(-1, -1, -1);

    optiling::TCubeTiling cubeTiling;
    int ret = mtiling.GetTiling(cubeTiling);
    if (ret == -1) { return ge::GRAPH_FAILED; }

    // Fill raw tiling buffer: [TCubeTiling bytes][Tail fields]
    auto *raw = context->GetRawTilingData();
    const uint32_t tilingBytes = static_cast<uint32_t>(sizeof(optiling::TCubeTiling));
    const uint32_t tailBytes = sizeof(uint32_t) * 4 + sizeof(float) * 3; // N,K,C,G + eps, htMin, htMax
    if (raw->GetCapacity() < tilingBytes + tailBytes) {
        return ge::GRAPH_FAILED;
    }
    // Save TCubeTiling
    uint8_t *buf = reinterpret_cast<uint8_t*>(raw->GetData());
    (void)memcpy(buf, &cubeTiling, sizeof(optiling::TCubeTiling));
    // Save tail
    uint32_t *uTail = reinterpret_cast<uint32_t*>(buf + sizeof(optiling::TCubeTiling));
    uTail[0] = N; uTail[1] = K; uTail[2] = C; uTail[3] = G;
    float *fTail = reinterpret_cast<float*>(uTail + 4);
    fTail[0] = eps; fTail[1] = htMin; fTail[2] = htMax;

    raw->SetDataSize(tilingBytes + tailBytes);

    // BlockDim: conservative bound; if framework honors TCubeTiling's internal core number, it's fine
    uint32_t blockDim = 24u;
    context->SetBlockDim(blockDim);

    // Workspace: we reuse GM output in-place for normalization later; no extra temp for activations.
    // Stats workspace not needed due to per-group recompute in normalization step.
    size_t *ws = context->GetWorkspaceSizes(1);
    ws[0] = 0;
    return ge::GRAPH_SUCCESS;
}

